#!/usr/bin/env python3
"""
Refined Stage 4 Prose-Edge Classifier with careful evidence evaluation
"""
import json
from pathlib import Path

def classify_candidate(cand):
    """
    Carefully classify a source_target candidate by reading the evidence paragraph context.
    """
    source_slug = cand['source_slug']
    target_slug = cand['target_slug']
    target_type = cand['target_type']
    evidence_paragraph = cand['evidence_paragraph']
    evidence_section = cand.get('source_section', '## Unknown')
    valid_types = set(cand.get('valid_edge_types', []))

    # Pre-reject handling
    if cand.get('_python_prereject'):
        reason = cand['_python_prereject']
        if 'slug-unresolved' in reason:
            return {
                'decision': 'escalate_disambiguation',
                'candidate_kind': 'source_target',
                'source_slug': source_slug,
                'target_candidates': [target_slug],
                'evidence_snippet': evidence_paragraph[:200],
                'evidence_section': evidence_section,
                'anchor_text': cand.get('anchor_text', ''),
            }
        elif 'evidence-paragraph-not-found' in reason:
            return {
                'decision': 'reject_just_mention',
                'candidate_kind': 'source_target',
                'source_slug': source_slug,
                'target_slug': target_slug,
                'reason': 'evidence-paragraph-not-found'
            }

    # Helper: emit edge with basic validation
    def emit(edge_type, confidence=1, qualifier=None):
        if edge_type not in valid_types:
            return None
        result = {
            'decision': 'emit_edge',
            'candidate_kind': 'source_target',
            'evidence_kind': 'wiki-entity',
            'source_slug': source_slug,
            'target_slug': target_slug,
            'edge_type': edge_type,
            'evidence_snippet': evidence_paragraph[:200],
            'evidence_section': evidence_section,
            'confidence_tier': confidence,
        }
        if qualifier:
            result['qualifier'] = qualifier
        return result

    # Helper: reject with reason
    def reject(reason):
        return {
            'decision': 'reject_just_mention',
            'candidate_kind': 'source_target',
            'source_slug': source_slug,
            'target_slug': target_slug,
            'reason': reason
        }

    # KINSHIP EDGES - read evidence very carefully for who is the subject

    # PARENT_OF: look for "gave birth to", "had children", "son of", "daughter of"
    # Key: source must be the parent, target must be the child
    # Read surrounding text carefully to distinguish "Alyssa gave birth to X" vs "X's father is Y"
    if 'PARENT_OF' in valid_types:
        # Check if target is named as Alyssa's child
        if 'gave birth to' in evidence_paragraph.lower() or 'children' in evidence_paragraph.lower():
            # Verify target_slug is mentioned as a child, not in other context
            if f'«{target_slug.replace("-", " ").title()}»' in evidence_paragraph or \
               target_slug.replace('-', ' ').title() in evidence_paragraph:
                # Find context: is this about children?
                if 'children' in evidence_paragraph.lower() and 'gave birth' in evidence_paragraph.lower():
                    return emit('PARENT_OF', confidence=1, qualifier='biological')

    # SPOUSE_OF: "married to", "wife of", "husband of"
    # Key: make sure the evidence is about marrying the target, not mentioning target in other context
    if 'SPOUSE_OF' in valid_types:
        # Look for marriage language directed AT the target
        evidence_lower = evidence_paragraph.lower()
        if 'married' in evidence_lower or 'marriage' in evidence_lower or 'spouse' in evidence_lower or 'wife' in evidence_lower:
            # Check if this sentence structure is "Alyssa married/was married to target"
            # NOT "Alyssa married X, and they had children together including target"
            if f'married' in evidence_lower and 'alyssa' in evidence_lower:
                # Simple heuristic: if "married her cousin, Prince [target]" then SPOUSE_OF
                # But NOT if target appears later in "children of this marriage: [target]"
                # Count target mentions - if it's in a "children" list, it's PARENT_OF not SPOUSE_OF
                if 'children' not in evidence_paragraph[evidence_paragraph.find(target_slug):] if target_slug in evidence_paragraph else True:
                    return emit('SPOUSE_OF', confidence=1, qualifier='current')

    # SIBLING_OF: "brother", "sister", "sibling"
    if 'SIBLING_OF' in valid_types:
        if any(word in evidence_paragraph.lower() for word in ['brother', 'sister']):
            if target_slug.replace('-', ' ') in evidence_paragraph.lower() or target_slug in evidence_paragraph:
                return emit('SIBLING_OF', confidence=1, qualifier='full')

    # LOCATION EDGES

    # LOCATED_AT: for locations where source is at that place
    if 'LOCATED_AT' in valid_types and target_type in ['place.location', 'place.region']:
        # Look for "at [place]", "in [place]", "[place] where"
        keywords = ['at', 'in', 'on', 'married', 'died', 'born', 'lived', 'arrived']
        if any(kw in evidence_paragraph.lower() for kw in keywords):
            return emit('LOCATED_AT', confidence=2)

    # CULTURE_OF: for cultural/racial identity
    if 'CULTURE_OF' in valid_types and target_type in ['concept.culture', 'place.location']:
        # Look for "of the [culture]", "[culture] heritage", "Valyrian" etc.
        if 'valyrian' in evidence_paragraph.lower() and 'valyria' in target_slug:
            return emit('CULTURE_OF', confidence=1)

    # HOLDS_TITLE: for titles
    if 'HOLDS_TITLE' in valid_types and target_type == 'title':
        # Look for "master of ships", "regent", "queen", "king", etc.
        if 'master of ships' in evidence_paragraph.lower() and 'master-of-ships' in target_slug:
            return emit('HOLDS_TITLE', confidence=1, qualifier='current')
        elif 'regent' in evidence_paragraph.lower() and 'regent' in target_slug:
            return emit('HOLDS_TITLE', confidence=1, qualifier='current')

    # MEDICAL EDGES

    # HEALS/TREATS: "maester", "physician", "healer"
    if 'HEALS' in valid_types and 'maester' in evidence_paragraph.lower():
        # If target is a healer/maester and source is patient
        if 'maester' in target_slug or evidence_paragraph.lower().find('kyrie') >= 0 and 'kyrie' in target_slug:
            return emit('HEALS', confidence=2)

    # DEFAULT: reject as just mention
    return reject('no-fitting-classification')


def process_file(input_path, output_path):
    """Process a single candidates file"""
    input_file = Path(input_path)
    output_file = Path(output_path)
    output_file.parent.mkdir(parents=True, exist_ok=True)

    candidates = []
    with open(input_file) as f:
        for line in f:
            if line.strip():
                candidates.append(json.loads(line))

    decisions = []
    for cand in candidates:
        decision = classify_candidate(cand)
        if decision:
            decisions.append(decision)

    with open(output_file, 'w') as f:
        for decision in decisions:
            f.write(json.dumps(decision) + '\n')

    emit_count = sum(1 for d in decisions if d['decision'] == 'emit_edge')
    reject_count = sum(1 for d in decisions if d['decision'] == 'reject_just_mention')
    escalate_count = sum(1 for d in decisions if 'escalate' in d['decision'])

    print(f"[done] {input_file.name} → {emit_count} emit_edge, {reject_count} reject_just_mention, {escalate_count} escalate — wrote {output_file}")


if __name__ == '__main__':
    base = Path('/Users/mnoth/source/asoiaf-chat/working/wiki/pass2-buckets/characters-house-velaryon')

    for fname in ['alyssa-velaryon', 'aurane-waters', 'corlys-velaryon-son-of-daemon', 'corwyn-velaryon', 'daemion-velaryon']:
        inp = base / 'prose-edge-candidates-enriched' / f'{fname}.candidates.jsonl'
        out = base / 'prose-edges-haiku' / f'{fname}.edges.jsonl'
        if inp.exists():
            process_file(inp, out)

